import{_ as e,o as r,c as a,ag as i}from"./chunks/framework.gU7RhlGX.js";const T=JSON.parse('{"title":"TuriX-CUA","description":"","frontmatter":{},"headers":[],"relativePath":"Agent/TuriX-CUA.md","filePath":"Agent/TuriX-CUA.md","lastUpdated":1776422487000}'),p={name:"Agent/TuriX-CUA.md"};function n(o,t,u,A,s,_){return r(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="turix-cua" tabindex="-1">TuriX-CUA <a class="header-anchor" href="#turix-cua" aria-label="Permalink to &quot;TuriX-CUA&quot;">​</a></h1><p>是一个让 AI 替你玩电脑的 AI 智能体。</p><p>它也是给 AI 装上眼睛和手，让它像人一样看着屏幕，动鼠标、敲键盘，帮你把活儿干了。</p><p>开源地址：<a href="https://github.com/TurixAI/TuriX-CUA" target="_blank" rel="noreferrer">https://github.com/TurixAI/TuriX-CUA</a></p><p>TuriX-CUA（Computer Use Agent）是一个基于 Python 的开源 Agent。它的核心逻辑非常暴力美学：</p><p>看（See）：每隔几秒截一张你屏幕的图。</p><p>想（Think）：把截图扔给多模态大模型，问它：“老铁，用户让我订机票，现在屏幕上这情况，我下一步该点哪？”</p><p>动（Act）：模型返回坐标，TuriX 控制你的鼠标移过去点击，或者在输入框里打字。</p>',8)])])}const d=e(p,[["render",n]]);export{T as __pageData,d as default};
